de><span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> NCCL_DEBUG</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">INFO</span></span>
